<script setup lang="ts">import { computed } from 'vue'; import { useRouter } from 'vue-router'; import { useGameStore } from '@/stores/game'; import CandidateAvatar from '@/components/CandidateAvatar.vue'; const router=useRouter(); const game=useGameStore(); const sorted=computed(()=>[...game.candidates].sort((a,b)=>b.answers-a.answers))</script>
<template><div class="center-wrap"><div class="panel xwide team-select-panel"><h2>ВЫБЕРИТЕ КАНДИДАТОВ В КОМАНДУ</h2><div class="candidate-grid selectable"><button v-for="c in sorted" :key="c.id" class="candidate-card" :class="{selected:game.teamIds.includes(c.id)}" @click="game.toggleTeam(c.id)"><CandidateAvatar :candidate="c" size="lg"/><h3>{{c.name}}</h3><small>{{c.role}}</small><ul><li v-for="s in c.skills" :key="s">{{s}}</li></ul><span class="picked">Выбрано ответов: {{c.answers}}</span></button></div><button class="btn primary block" :disabled="!game.teamIds.length" @click="router.push('/team')">Принять в команду ({{game.teamIds.length}}/3)</button></div></div></template>
